//$Id$
import { NULL, TRANSPARENT } from '../../core/zc-constants';
import { d3_rgb } from '../../core/d3-constants';

// TODO: work with config. remove 'background-color' with 'fillColor'
function LegendBackgroundHtmlParser(spec) {
    let config = spec.config,
        backgroundSpec = parseBackground(config.background),
        borderSpec = parseBorder(config.border),
        shadowSpec = parseShadow(config.shadow);

    return {
        ...backgroundSpec,
        ...borderSpec,
        ...shadowSpec
    };
}

function parseBackground(config = {}) {
    let { color = TRANSPARENT, alpha } = config,
        rgb = d3_rgb(color.toString());

    return { 'background-color': `rgba(${rgb.r},${rgb.g},${rgb.b},${alpha})` };
}

function parseBorder(config = {}) {
    let { show, size, style, color, radius } = config;

    if (show) {
        return {
            border: `${+size}px ${style} ${color}`,
            'border-radius': `${radius}px`
        };
    }

    return { border: NULL };
}

function parseShadow(config = {}) {
    let { show, x, y, blur, color, inset } = config;

    if (show) {
        return { 'box-shadow': `${x}px ${y}px ${blur}px ${color}${inset ? ' inset' : ''}` };
    }

    return { 'box-shadow': NULL };
}

export { LegendBackgroundHtmlParser };
